#!/usr/bin/env python3"""Simple Jira connection test to debug issues"""import asyncioimport osfrom dotenv import load_dotenvfrom autogen_ext.tools.mcp import StdioServerParams, McpWorkbenchload_dotenv()async def test_jira_connection():    """Test basic Jira connectivity and search."""    def get_required_env(key: str) -> str:        value = os.getenv(key)        if not value:            raise RuntimeError(f"{key} environment variable not found")        return value    jira_server_params = StdioServerParams(        command="uvx",        args=["mcp-atlassian"],        env={            "JIRA_URL": get_required_env("JIRA_URL"),            "JIRA_USERNAME": get_required_env("JIRA_USERNAME"),            "JIRA_API_TOKEN": get_required_env("JIRA_API_TOKEN"),            "TOOLSETS": "all",  # Set explicit toolsets to avoid warning        },        read_timeout_seconds=60,    )    async with McpWorkbench(jira_server_params) as jira:        print("🔗 Connected to Jira MCP server")        # List available tools        try:            tools = await jira.list_tools()            print(f"📋 Available tools: {len(tools)} found")            for tool in tools:                tool_name = (                    tool.get("name", "Unknown")                    if isinstance(tool, dict)                    else getattr(tool, "name", "Unknown")                )                print(f"  - {tool_name}")        except Exception as e:            print(f"❌ Error listing tools: {e}")            return        # Test different search queries        queries_to_test = [            {"jql": "project = KAN", "description": "All issues in KAN project"},            {                "jql": "project = KAN AND issuetype = Bug",                "description": "Bugs in KAN project",            },            {"jql": "key >= KAN-1", "description": "Issues from KAN-1 onwards"},            {"jql": "key = KAN-5", "description": "Specific issue KAN-5"},            {                "jql": "project = KAN ORDER BY created DESC",                "description": "Recent KAN issues",            },        ]        for query_info in queries_to_test:            jql = query_info["jql"]            desc = query_info["description"]            print(f"\n🔍 Testing: {desc}")            print(f"   JQL: {jql}")            try:                # Call jira_search function directly                result = await jira.call_tool(                    "jira_search",                    {                        "jql": jql,                        "fields": "summary,status,priority,description,created,reporter,assignee",                        "limit": 10,                    },                )                if hasattr(result, "content"):                    import json                    data = json.loads(result.content)                    total = data.get("total", 0)                    issues = data.get("issues", [])                    print(                        f"✅ Success! Found {total} issues, returned {len(issues)} issues"                    )                    if issues:                        for issue in issues[:3]:  # Show first 3                            key = issue.get("key", "Unknown")                            summary = issue.get("fields", {}).get(                                "summary", "No summary"                            )                            print(f"   📝 {key}: {summary}")                    else:                        print("   ℹ️  No issues returned")                else:                    print(f"✅ Result: {result}")            except Exception as e:                print(f"❌ Error with query '{jql}': {e}")if __name__ == "__main__":    asyncio.run(test_jira_connection())